import json, sys

for line in sys.stdin:
    line = line.strip()
    if not line:
        continue
    try:
        data = json.loads(line)
    except:
        continue

    msg_type = data.get('type')

    if msg_type == 'message':
        msg = data.get('message', {})
        role = msg.get('role', '')
        content = msg.get('content', '')
        text = ''
        if isinstance(content, list):
            for block in content:
                if isinstance(block, dict) and block.get('type') == 'text':
                    text += block.get('text', '')
        elif isinstance(content, str):
            text = content

        # Summarize tool calls
        tool_calls = []
        for block in content if isinstance(content, list) else []:
            if isinstance(block, dict) and block.get('type') == 'toolCall':
                tc = block.get('arguments', {})
                tool_calls.append(tc.get('command', tc.get('description', tc.get('queries', ''))))

        if role == 'user':
            print(f'=== USER ===\n{text[:500]}')
        elif role == 'assistant':
            # Only show text parts, skip tool calls
            text_parts = []
            if isinstance(content, list):
                for block in content:
                    if isinstance(block, dict) and block.get('type') == 'text' and not block.get('thinking'):
                        text_parts.append(block.get('text', ''))
            text = ''.join(text_parts)
